    let maxIndex = nums.length - 1;

    function sieve(n) {
        if (n < 2) return new Array(n + 1).fill(false);
        let isPrime = new Array(n + 1).fill(true);
        isPrime[0] = isPrime[1] = false;
        for (let i = 2; i * i <= n; i++) {
            if (isPrime[i]) {
                for (let j = i * i; j <= n; j += i) {
                    isPrime[j] = false;
                }
            }
        }
        return isPrime;
    }

