    val isPrime = sieve(maxIndex)
    var sumA = 0L
    var sumB = 0L
    for (i <- 0 until nums.length) {
        if (isPrime(i)) {
            sumA += nums(i)
        } else {
            sumB += nums(i)
        }
    }
    math.abs(sumA - sumB)
}
